  color: var(--link-external-color);
  cursor: var(--cursor-link);
  filter: var(--link-external-filter);
  font-family: var(--retroma-canvas-custom-font);
  font-weight: var(--link-weight);
  outline: oklch(0.5 0.12 26.4067) none 0px;
  text-decoration: underline;
  text-decoration-color: oklch(0.5 0.12 26.4067);
  text-decoration-line: var(--link-external-decoration);
  text-decoration-style: solid;
  text-decoration-thickness: var(--link-decoration-thickness);
  transition: opacity 0.14s ease-in-out;
